    fn tokenToSymbol(self: *Parser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 50,
            .@"indent" => 54,
            .@"outdent" => 55,
            .@"string_dq" => 63,
            .@"integer" => 110,
            .@"real" => 111,
            .@"string_sq" => 112,
            .@"true" => 113,
            .@"false" => 114,
            .@"assign" => 61,
            .@"colon" => 67,
            .@"comma" => 68,
            .@"not_sym" => 72,
            .@"question" => 73,
            .@"star" => 74,
            .@"lbracket" => 75,
            .@"rbracket" => 76,
            .@"bar" => 79,
            .@"minus" => 101,
            .@"dot" => 103,
            .@"lparen" => 106,
            .@"rparen" => 107,
            .@"at" => 117,
            .@"lbrace" => 118,
            .@"rbrace" => 121,
            .@"lt" => 140,
            .@"gt" => 141,
            .@"plus" => 145,
            .@"slash" => 146,
            .@"percent" => 147,
            .@"arrow" => 71,
            .@"fat_arrow" => 86,
            .@"nullish" => 87,
            .@"plus_assign" => 96,
            .@"minus_assign" => 97,
            .@"star_assign" => 98,
            .@"slash_assign" => 99,
            .@"const_assign" => 100,
            .@"pipe" => 135,
            .@"or_sym" => 136,
            .@"and_sym" => 137,
            .@"eq" => 138,
            .@"ne" => 139,
            .@"le" => 142,
            .@"ge" => 143,
            .@"dotdot" => 144,
            .@"power" => 148,
            else => 2, // error
        };
    }

    fn identToSymbol(self: *Parser, token: Token) u16 {
        const text = self.source[token.pos..][0..token.len];
        if (text.len == 0) return SYM_IDENT;
        if (self.try_ident_as_keyword(token, text)) |sym| return sym;
        return SYM_IDENT;
    }

    fn try_ident_as_keyword(self: *Parser, token: Token, text: []const u8) ?u16 {
        _ = token;
        const state = self.state_stack.getLast();
        if (rip.keyword_as(text)) |id| {
            const id_idx = @intFromEnum(id);
            const sym = keyword_to_symbol[id_idx];
            if (sym != 0 and getAction(state, sym) != 0) {
                self.last_matched_id = @intCast(id_idx);
                return sym;
            }
            const fallback = keyword_fallback_symbol;
            if (fallback != 0 and getAction(state, fallback) != 0) {
                self.last_matched_id = @intCast(id_idx);
                return fallback;
            }
        }
        return null;
    }

    pub fn parseProgram(self: *Parser) !Sexp {
        self.injected_token = SYM_program_START;
        return self.doParse(SYM_program);
    }
    pub fn parseExpr(self: *Parser) !Sexp {
        self.injected_token = SYM_expr_START;
        return self.doParse(SYM_expr);
    }
};

// Symbol IDs
const SYM_program: u16 = 3;
const SYM_program_START: u16 = 123;
const SYM_expr: u16 = 4;
const SYM_expr_START: u16 = 125;
const SYM_IDENT: u16 = 57;

// Mapping from rip.keyword_id to grammar symbol IDs (computed at comptime)
const keyword_to_symbol = blk: {
    var arr: [512]u16 = .{0} ** 512;
    if (@hasField(rip.keyword_id, "NEWLINE")) arr[@intFromEnum(rip.keyword_id.NEWLINE)] = 50;
    if (@hasField(rip.keyword_id, "PUB")) arr[@intFromEnum(rip.keyword_id.PUB)] = 51;
    if (@hasField(rip.keyword_id, "EXTERN")) arr[@intFromEnum(rip.keyword_id.EXTERN)] = 52;
    if (@hasField(rip.keyword_id, "EXPORT")) arr[@intFromEnum(rip.keyword_id.EXPORT)] = 53;
    if (@hasField(rip.keyword_id, "INDENT")) arr[@intFromEnum(rip.keyword_id.INDENT)] = 54;
    if (@hasField(rip.keyword_id, "OUTDENT")) arr[@intFromEnum(rip.keyword_id.OUTDENT)] = 55;
    if (@hasField(rip.keyword_id, "FUN")) arr[@intFromEnum(rip.keyword_id.FUN)] = 56;
    if (@hasField(rip.keyword_id, "IDENT")) arr[@intFromEnum(rip.keyword_id.IDENT)] = 57;
    if (@hasField(rip.keyword_id, "SUB")) arr[@intFromEnum(rip.keyword_id.SUB)] = 58;
    if (@hasField(rip.keyword_id, "USE")) arr[@intFromEnum(rip.keyword_id.USE)] = 59;
    if (@hasField(rip.keyword_id, "ALIAS")) arr[@intFromEnum(rip.keyword_id.ALIAS)] = 60;
    if (@hasField(rip.keyword_id, "TEST")) arr[@intFromEnum(rip.keyword_id.TEST)] = 62;
    if (@hasField(rip.keyword_id, "STRING_DQ")) arr[@intFromEnum(rip.keyword_id.STRING_DQ)] = 63;
    if (@hasField(rip.keyword_id, "ENUM")) arr[@intFromEnum(rip.keyword_id.ENUM)] = 64;
    if (@hasField(rip.keyword_id, "ERROR")) arr[@intFromEnum(rip.keyword_id.ERROR)] = 65;
    if (@hasField(rip.keyword_id, "STRUCT")) arr[@intFromEnum(rip.keyword_id.STRUCT)] = 66;
    if (@hasField(rip.keyword_id, "AS")) arr[@intFromEnum(rip.keyword_id.AS)] = 78;
    if (@hasField(rip.keyword_id, "IF")) arr[@intFromEnum(rip.keyword_id.IF)] = 80;
    if (@hasField(rip.keyword_id, "ELSE")) arr[@intFromEnum(rip.keyword_id.ELSE)] = 81;
    if (@hasField(rip.keyword_id, "WHILE")) arr[@intFromEnum(rip.keyword_id.WHILE)] = 82;
    if (@hasField(rip.keyword_id, "FOR")) arr[@intFromEnum(rip.keyword_id.FOR)] = 83;
